def check(cfg, policy):
    v = []
    if cfg["trains_on_customer_data"]:
        v.append("trains on data")
    if cfg["retention_days"] > policy["max_retention_days"]:
        v.append(f"retention {cfg['retention_days']}>" 
                 f"{policy['max_retention_days']}")
    if not cfg["region_pinning"]:
        v.append("no region pinning")
    return v
